import{_ as n,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"38. Prevention And Management Of Workplace Bullying","description":"","frontmatter":{"title":"38. Prevention And Management Of Workplace Bullying","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["ohs"]},"headers":[],"relativePath":"ebas/mspp/workforce-management/38-prevention-and-management-of-workplace-bullying.md","filePath":"ebas/mspp/workforce-management/38-prevention-and-management-of-workplace-bullying.md"}'),i={name:"ebas/mspp/workforce-management/38-prevention-and-management-of-workplace-bullying.md"};function r(s,e,p,l,g,c){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_38-prevention-and-management-of-workplace-bullying" tabindex="-1">38. Prevention And Management Of Workplace Bullying <a class="header-anchor" href="#_38-prevention-and-management-of-workplace-bullying" aria-label="Permalink to &quot;38. Prevention And Management Of Workplace Bullying&quot;">​</a></h1><p><strong>38.1</strong> Purpose This clause concerns the prevention and management of Workplace Bullying and requires Employers to take actions consistent with their obligations under the OHS Act. Workplace Bullying is an occupational health and safety risk.</p><p><strong>38.2</strong> Definitions Workplace Bullying is where:</p><p><strong>a.</strong> an individual or group of individuals repeatedly behaves unreasonably towards a worker or a group of workers at work; and,</p><p><strong>b.</strong> the behaviour creates a risk to health and safety.</p><p><strong>38.3</strong> Prevention - General</p><p><strong>a.</strong> Employers have a duty under the OHS Act to provide and maintain, so far as is reasonably practicable, a working environment that is safe and without risks to health.</p><p><strong>b.</strong> Employer obligations include:</p><p><strong>(i)</strong> providing and maintaining systems of work that are, so far as is reasonably practicable, safe and without risks to health;</p><p><strong>(ii)</strong> consulting with Employees who are or who are likely to be directly affected by a health and safety matter.</p><p><strong>c.</strong> Prevention is the key to providing a safe working environment.</p><p><strong>38.4</strong> Prevention - Policy</p><p><strong>a.</strong> Each Employer will have a workplace policy and procedure for workplace bullying.</p><p><strong>b.</strong> A workplace policy should state:</p><p><strong>(i)</strong> a commitment to providing Employees with a healthy and safe working environment;</p><p><strong>(ii)</strong> the standard of behaviour expected of all Employees, including examples of what is and what is not workplace bullying;</p><p><strong>(iii)</strong> how the policy applies in connection with work and work-related events and activities;</p><p><strong>(iv)</strong> that the policy covers all communication, including text messages, email and social media;</p><p><strong>(v)</strong> how and where Employees can report allegations of Workplace Bullying;</p><p><strong>(vi)</strong> that reports of Workplace Bullying will be taken seriously and the Employer will respond impartially and confidentially;</p><p><strong>(vii)</strong> what can happen if the policy is not followed;</p><p><strong>(viii)</strong> how the Employer will respond to allegations of Workplace Bullying that have been reported;</p><p><strong>(ix)</strong> how reports will be investigated; and</p><p><strong>(x)</strong> where to get more information.</p><p><strong>38.5</strong> Managing Workplace Bullying – General Principles Where it is necessary to conduct an investigation regarding potential Workplace Bullying, the following principles will apply:</p><p><strong>a.</strong> The Employee who is the subject of the concern will be provided with natural justice including but not limited to:</p><p><strong>(i)</strong> The Employee is informed of the specific allegations against them in writing;</p><p><strong>(ii)</strong> the process to be followed is explained to the Employee;</p><p><strong>(iii)</strong> the Employee is informed that they may be represented by their Union representative, or other advocate, at each stage of the process;</p><p><strong>(iv)</strong> the Employee is informed of the purpose of any meetings that may be held;</p><p><strong>(v)</strong> the Employee is provided with an opportunity to respond via documentation, an interview or a combination of both; and</p><p><strong>(vi)</strong> the investigator and, in turn, the decision-maker, must act in good faith and without bias.</p><p><strong>b.</strong> To act without bias:</p><p><strong>(i)</strong> means the person conducting the investigation has no preconceived opinions, vested interests or prior personal involvement in the matter; and</p><p><strong>(ii)</strong> does not necessarily mean excluding a person from the same organisation as the Employee from conducting an investigation or making a decision.</p><p><strong>c.</strong> The Employer shall provide an unredacted report to the Employees and their representative/s, including the Union where relevant, upon request.</p><p><strong>38.6</strong> Where an external investigator is appointed</p><p><strong>a.</strong> Where the Employer decides to appoint an external investigator, the Employer shall either:</p><p><strong>(i)</strong> Select an investigator from the DH ‘preferred provider’ list, or</p><p><strong>(ii)</strong> Appoint an investigator following timely consultation with the representative of the Employee parties, including the Union, where relevant. The Employer may appoint an investigator without consultation where no response is received from the Union within 5 days following the Union being notified.</p><p><strong>b.</strong> Consultation in this clause 38.6 has its ordinary meaning and does not refer to consultation as set out at <a href="/eba/ebas/mspp/employment/30-consultation.html">clause 30</a> and shall be conducted efficiently having regard for the health and safety of the Employees.</p><p><strong>38.7</strong> More information Further information about workplace bullying and principles to manage and resolve bullying matters can be found at:</p><p><strong>a.</strong> www.worksafe.vic.gov.au/bullying-workplace</p><p><strong>b.</strong> Victorian Public Sector Standards Commissioner’s Guide – Managing Poor Behaviour in the Workplace.</p><p>HIGHER QUALIFICATION ALLOWANCES</p><p>Plain language terms: bullying, workplace bullying.</p>',46)])])}const m=n(i,[["render",r]]);export{d as __pageData,m as default};
